import { Component, State, EventEmitter, Event, Prop, h } from '@stencil/core';
import { CheckedIcon } from '../../svg/Svg';

@Component({
  tag: 'checkbox-component',
  styleUrl: 'checkbox-component.css',
  shadow: true,
})
export class CheckboxComponent {
  @Prop({ mutable: true, reflect: true }) checked: boolean = false;
  @Prop() label: string = '';
  @Prop() disabled: boolean = false;
  @Event() checkboxChange: EventEmitter<boolean>;
  @Prop() showBorder: boolean = false;
  @Prop() colors?: string;
  @State() showKeyboardFocus: boolean = false;


  private getCheckmarkIcon() {
    return (
      <CheckedIcon className="checkbox-icon" />
    );
  }

  private onInputChange = (event: Event) => {
    const input = event.target as HTMLInputElement;
    this.checked = input.checked;
    this.checkboxChange.emit(this.checked);
  };

  private getColors(): string[] {
    if (!this.colors) return [];
    return this.colors.split(',').map(c => c.trim());
  }

  componentDidLoad() {
    window.addEventListener('keydown', this.handleGlobalKeyDown);
    window.addEventListener('mousedown', this.handleGlobalMouse);
  }

  disconnectedCallback() {
    window.removeEventListener('keydown', this.handleGlobalKeyDown);
    window.removeEventListener('mousedown', this.handleGlobalMouse);
  }

  private handleGlobalKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Tab') {
      this.showKeyboardFocus = true;
    }
  }

  private handleGlobalMouse = () => {
    this.showKeyboardFocus = false;
  }

  render() {
    return (
      <div
        class={`checkbox-container${this.showBorder ? ' has-border' : ''}${this.showKeyboardFocus ? ' focus-visible-wrapper' : ''}`}
      >
        <label class="checkbox-label">
          <div class="checkbox-row">
            <span class="checkbox-input-wrapper">
              <input
                type="checkbox"
                checked={this.checked}
                disabled={this.disabled}
                onChange={this.onInputChange}
                class="checkbox-input"
              />
              {this.checked && this.getCheckmarkIcon()}
            </span>
            {this.getColors().length === 3 && (
              <div class="color-swatch">
                {this.getColors().map(color => (
                  <div class="swatch-color" style={{ background: color }}></div>
                ))}
              </div>
            )}
            <span class="checkbox-text">{this.label}</span>
          </div>
        </label>
      </div>
    );
  }
}
